def test_phase1_auth_required_contract(tmp_path: Path):
    """Require API key on protected routes and enforce normalized unauthorized responses."""
    settings = _build_test_settings(tmp_path / "ragbench-auth.sqlite3", api_key="phase1-secret")
    app = create_app(settings)

    with app.test_client() as auth_client:
        unauthorized = auth_client.get("/api/v1/benchmarks/runs", headers={"Host": "testserver"})
        _assert_error_contract(
            unauthorized,
            expected_status=401,
            expected_code="unauthorized",
            expected_message="api_key_invalid",
        )

        invalid_key = auth_client.get(
            "/api/v1/benchmarks/runs",
            headers={"Host": "testserver", "X-API-Key": "wrong"},
        )
        _assert_error_contract(
            invalid_key,
            expected_status=401,
            expected_code="unauthorized",
            expected_message="api_key_invalid",
        )

        authorized = auth_client.get(
            "/api/v1/benchmarks/runs",
            headers={"Host": "testserver", "X-API-Key": "phase1-secret"},
        )
        assert authorized.status_code == 200


